/* com.matjzing.mapper.FrontCandidateMapper.insertFrontCandidate */
INSERT INTO CANDIDATE (
	  TOPIC_SEQ /**/
	, NAME /**/
	, INFO /**/
	, PRICE /**/
	, IMAGE_URL /**/
	, LINK_URL /**/
	, IS_FIXED /**/
	, USE_YN /**/
	, REGISTER_SEQ /**/
	, REGISTER_IP /**/
	, REGISTRATION_DT /**/
	, UPDATER_SEQ /**/
	, UPDATER_IP /**/
	, UPDATE_DT /**/
) VALUES (
	  #{topicSeq}
	, #{name}
	, #{price}
	, #{imageUrl}
	, #{linkUrl}
	, #{isFixed}
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)
